class Vehicle:
    def __init__(self, brand, speed):
        self.brand = brand
        self.speed = speed

    def info(self):
        print(f"{self.brand} - {self.speed} km/h")

class Car(Vehicle):
    def __init__(self, brand, speed, doors):
        super().__init__(brand, speed)  # Call parent!
        self.doors = doors

    def info(self):
        super().info()
        print(f"  Doors: {self.doors}")

class Motorcycle(Vehicle):
    def info(self):
        super().info()
        print("  Type: Two-wheeler 🏍️")

car = Car("Toyota", 180, 4)
moto = Motorcycle("Ducati", 250)
car.info()
print()
moto.info()
